var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……지진?","JPN":"……地震？","ENG":"...An earthquake?","TWN":"……地震？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"당장 알아보겠습니다.","JPN":"すぐ調べてきます。","ENG":"I’ll go take a look.","TWN":"我們立刻去看看！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래요. 정말, 빨리 헤이븐 랜드로 올라가야지 안 되겠네. 여러모로 귀찮은 일이 계속……","JPN":"お願いします。もう、早くヘイブンランドに戻らないといけないわね。次々と面倒なことが……","ENG":"All right then. I should head back up to Havenland soon. It’s just one annoying thing after─","TWN":"嗯嗯，我還得趕快上去天堂樂園呢。真是的，麻煩的事一大堆……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"한 번에 뚫릴 줄 알았는데. 이건 너무 멋없잖아?","JPN":"一度であくと思ったのに。これちょっとカッコ悪くない？","ENG":"Bummer. I thought I could take it out in one blow.","TWN":"我還以為一腳就可以踹破，結果一點也不帥！"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시…… 충분히 멋있긴 한데…… 꼭 이렇게 요란하게 했어야 됐을까?","JPN":"ドロシーちゃん……十分カッコよかったけど……ここまで派手にやる必要があったの？","ENG":"Dorothy... That was pretty cool and all, but... Did we have to make a scene?","TWN":"桃樂絲……帥是很帥…不過你非得動作這麼大嗎？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"쉬이. 토토. 벼, 별일 아냐! 잠깐 큰소리가 난 것뿐이니까 진정해.","JPN":"シーっ。トト。た、大したことじゃないよ！　ちょっと大きな音がしただけだから落ち着いて。","ENG":"Shh, Toto. I-it’s nothing, so calm down. The loud noise is gone now.","TWN":"噓，托托，沒事沒事！只是聲音有點大而已，你別激動。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이럴 줄 알았으면 빈말이라도 네가 해결해 보라는 얘긴 안 했을 텐데.","JPN":"こうなると知ってたら、お世辞にもアナタに解決してみろという話はしなかったのに。","ENG":"I would have never asked you if I had known this was going to happen.","TWN":"早知如此，我就不假裝客氣讓你去處理。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"문 해킹하는 시간이 얼마나 걸린다고. 그 짧은 시간도 기다리기가 그렇게 어려웠어?","JPN":"扉なんて瞬く間にハッキングできるんだ。その短い時間も待てなかった？","ENG":"It would have only taken a few minutes to hack the door. You couldn't wait a few minutes?","TWN":"駭入門鎖是要花多少時間，你連這麼短的時間都等不及嗎？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이렇게 하면 금방 들어오는데 뭐하러?","JPN":"こうやったらすぐ入れるのになんで？","ENG":"I busted it wide open in no time, so why bother?","TWN":"那麼麻煩幹嘛，這樣用踹的不是很快嗎？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그래. 덕분에 아주 온 난리 다 피워서 지원팀 다 몰려오게 생겼지만.","JPN":"そうだね。おかげさまで、騒ぎすぎて応援班が全部押し寄せてきそうだけど。","ENG":"Yeah. Thanks to you, all the support team will be running over here.","TWN":"是很快，但也拜你所賜，引起這麼大的騷動，現在整個支援組都知道我們在這。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"싸우지 마, 얘들아. 지금 그럴 때야?","JPN":"みんな、ケンカしないで。そういう場合じゃないでしょ？","ENG":"Girls, don’t fight. We don’t have time for that.","TWN":"你們不要吵架，現在是吵架的時候嗎？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"메이드 언니 몰래 와서 가슴 쫄려 죽겠는데…….","JPN":"メイドのお姉さんに黙って、こっそり来たから気が気じゃないのに……","ENG":"I’m just worried about what the maid will do to us if she finds out...","TWN":"瞞著女僕姊姊跑到這裡來，我都已經快緊張死了……"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그건 걱정 마. 허락만 못 받았지, 다른 건 다 받은 거나 마찬가지니까.","JPN":"それは心配すんなよ。取れなかったのは許可だけで、他のものは全部取ったようなもんだから。","ENG":"Don’t worry. She may not have granted us permission, but she did grant us everything else.","TWN":"你放心啦，她只是嘴上沒說，但其實是默許。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"오늘은 다른 때보다 밤이 긴 날이라 다들 헤이븐 랜드에 올라가서 비어 있을 거랬고, 위저드 좌표도 정확하게 찍어 줬어.","JPN":"今日はいつもより夜が長い日だから、みんなヘイブンランドに上がっていて手薄だろうって言っていたし、ウィザードの座標も正確に示してくれた。","ENG":"She gave us the exact coordinates and even told us that it would be mostly empty because everyone would be up in Havenland because the night was longer than usual.","TWN":"她說今天的夜特別長，大家一定會上天堂樂園，組織裡一定沒人的，還告訴我們魔法師的座標。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이 정도 알려준 거면 분명 몰래 침입하라는 얘기야.","JPN":"ここまで教えてくれたってことは、きっとこっそり侵入してもいいってこと。","ENG":"If she told us that much, she wanted us to infiltrate this place.","TWN":"她跟我們說這麼多，擺明是要我們偷偷潛入的意思。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그건 아닐 것 같은데…….","JPN":"それは違うと思うよ……","ENG":"I don’t think so...","TWN":"應該不是吧……"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"치사하게 우리만 빼놓고 작전 진행할 생각이었다니까? 침입 명단에 우리 셋 이름만 쏙 빠져 있었거든.","JPN":"私たちなしで作戦を進める気だったんだ、ズルくない？　侵入リストに私たち3人の名前だけなかったんだ。","ENG":"She was trying to hog the mission all to herself. She even left our names off the infiltration list.","TWN":"就說她是將我們排除在作戰之外！入侵名單中偏偏就沒有我們三個人的名字。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"참고로 그 명단은 수아가 해킹해서 빼 온 거야. 역시 유능해.","JPN":"ちなみに、そのリストはコトリがハッキングして盗んできたやつだ。やっぱり有能だね。","ENG":"By the way, Skia’s the one who hacked in and got the list. Good job.","TWN":"說到這個，那份名單還是蘇亞駭來的，果然有兩下子喔！"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"훗. 기본이지.","JPN":"ふっ。このくらいは普通だよ。","ENG":"Heh. Easy.","TWN":"呵，小Case。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"흐아… 난 모르겠다……. 이미 돌이킬 수도 없는 노릇이고.","JPN":"ふあぁ……私は知らない……もう引き返せないし。","ENG":"Ooh... I dunno... We’ve gone too far to turn back now...","TWN":"哀…就這樣吧……現在說這些也無濟於事。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그런데…… 저…… 여기는 사람도, 경비도 없는 곳이라고 하지 않았어?","JPN":"ところで……あの……ここって人も、警備もないって言ってなかった？","ENG":"But, uh... Didn’t you say this place would be empty, with no guards?","TWN":"不過……她不是說……這裡都不會有人看守嗎？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그랬지?","JPN":"そうだったけど？","ENG":"Yeah?","TWN":"是吧？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저 사람들은……?","JPN":"あの人たちは……？","ENG":"Then who are they...?","TWN":"那那些人是……？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이 기분은 마치……","JPN":"この気分はまるで……","ENG":"This feels like...","TWN":"我現在的心情……"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"음식물 쓰레기 태우는 기분?","JPN":"生ゴミを燃やしてるような気分？","ENG":"Burning toxic waste?","TWN":"感覺就像廚餘回收場？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아니. 그보다는…… 꼭 시체 태우는 냄새가 나는 기분이야.","JPN":"いや。それよりは……まるで死体を燃やす匂いがするような気分だ。","ENG":"No. It is more like... The smell of burning bodies.","TWN":"不是，感覺更像是……屍體火化的味道。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……그거 왠지 비유로만 느껴지지는 않아서 좀 으스스한 걸.","JPN":"……それ、どうも単なるたとえっぽくなくて、ちょっとぞっとするぞ。","ENG":"I don’t really get the metaphor, so that’s kinda creepy.","TWN":"……這是什麼詭異的譬喻？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이게 다 도로시 때문이야. 조용히 들어왔어야 했는데.","JPN":"全部ドロシーのせいだ。静かに入るべきだったのに。","ENG":"This is all Dorothy’s fault. We should have sneaked our way in.","TWN":"都是桃樂絲你害的，剛剛應該要安靜地潛入這裡的。"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"큰일났네……. 토토, 우리 입마개 풀까?","JPN":"大変なことになったね……トト、口輪外そうか？","ENG":"Oh no... Toto, let me get that muzzle off you, okay?","TWN":"糟糕……托托，要拿掉口罩嗎？"},"stage":{"bg":"NIGHTMARE_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"저 애들은…… 도로시? 허수아?","JPN":"あの子たちは……ドロシー？　コトリ？","ENG":"Wait, you’re... Dorothy? Skia?","TWN":"她們是……桃樂絲？禾蘇亞？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SMILE_NPC_OZ_C","text":{"KOREA":"어어? 오즈 녀석들이잖아?!","JPN":"あれ？　オズの奴らじゃねえか！？","ENG":"Huh?! It’s those OZ rascals!!","TWN":"喔？這不是奧茲國的丫頭們嗎？！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_C","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"……도로시. 겁도 없이 돌아오다니.","JPN":"……ドロシー。のこのこ戻って来るとは。","ENG":"Dorothy... How dare you come back here.","TWN":"……桃樂絲，你膽子還真大，竟然跑回來？！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_C","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SMILE_NPC_OZ_C","text":{"KOREA":"이번에야 말로 본때를 보여주자고. 오늘은 든든한 헤이븐 조직원 분들도 계시니까!","JPN":"今度こそ目にもの見せてやろうぜ。今日は心強いヘイブンの組織員もいるからさ！","ENG":"We’ll show you who’s boss this time! We even have Haven members on our side this time!","TWN":"今天天堂的成員也都在，你們要倒大楣啦！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_C","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SMILE_NPC_OZ_C","text":{"KOREA":"……그런데 우리 마담은 그새 어디 가셨지?","JPN":"……ところで、マダムはどこに行かれたんだ？","ENG":"But uh... Where did Madam go?","TWN":"……不過夫人怎麼突然不見啦？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_C","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"마담께선 중요한 일처리를 위해 먼저 나가셨다. 너흰 신경 꺼라.","JPN":"マダムは重要な仕事のために先に出られた。お前らは気にするな。","ENG":"Madam left to take care of other business. Focus on the task at hand.","TWN":"夫人有要事在身，必須先去處理，你們管好自己就好！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"오즈라면, 헤이븐 형님을 배신한 자들이로군.","JPN":"オズなら、ヘイブン兄貴を裏切った奴らだな。","ENG":"OZ? So those are the brats that betrayed the boss...","TWN":"奧茲國，就是背叛天堂大哥的傢伙吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"배신자들에게 자비는 없다. 오늘이 마지막 밤이 되게 해주지!","JPN":"裏切り者に慈悲はない。今夜を最後の夜にしてやる！","ENG":"No mercy for traitors. Tonight will be your last day on earth!","TWN":"不需要對叛徒手下留情，今天就是她們的忌日！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"쟤 뭐래?","JPN":"あいつ、何だって？","ENG":"What’s up with him?","TWN":"他在說什麼？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"마지막 밤이 되게 해주겠대.","JPN":"最後の夜にしてやるって。","ENG":"He said he will make this our last day on earth.","TWN":"他說今天就是我們的忌日。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아직도 자기들이 우리 약점 쥐고 있는 줄 아나 봐? 바보들.","JPN":"まだ自分たちが私たちの弱み握ってると思ってるのか？　バカだな。","ENG":"They still think they have our weaknesses. Stupid heads.","TWN":"那群傻瓜，還以為我們現在還有把柄在他們手上嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"바보들. 토토보다 머리가 나쁜 게 분명해.","JPN":"ばかだね。きっとトトより頭悪いんだよ。","ENG":"Stupid heads. I’m certain they’re dumber than Toto.","TWN":"真的傻，簡直比托托還要笨。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아앗. 토토. 칭찬이야. 화내지 마.","JPN":"ああっ。トト。褒めてるんだよ。怒らないで。","ENG":"Oh! Don’t get mad, Toto. It’s a compliment.","TWN":"哎呀，托托，我是在稱讚你，你別生氣。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"마하의 속도를 보여주지. 눈 깜짝할 새…… 끝날 거야.","JPN":"マッハのスピードを見せてやるよ。あっという間に……終わるぞ。","ENG":"I’ll show you what Mach speed looks like. It’ll all be over... before you know it.","TWN":"讓你們見識一下馬赫的速度，轉眼間……就立刻結束。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};